#!/bin/bash\necho "=== 问卷系统演示 ===\necho "1. 启动后端服务..."\nnpm start &\nBACKEND_PID=$!\necho "后端PID: $BACKEND_PID"\necho "等待后端启动..."\nsleep 5\necho "2. 启动前端服务..."\ncd frontend\nnpm install\nnpm run dev &\nFRONTEND_PID=$!\necho "前端PID: $FRONTEND_PID"\necho "等待前端启动..."\nsleep 10\necho "3. 系统启动完成！"\necho "后端: http://localhost:3000"\necho "前端: http://localhost:5173"\necho "测试用户: test1@example.com / 123456"\necho "按 Ctrl+C 停止服务"\ntrap "echo 停止服务...; kill $BACKEND_PID $FRONTEND_PID; exit" INT\nwait"
